  label: string;
}

export function getServiceTimes(lang: Lang = 'en'): { heading: string; items: ServiceTime[] } {
  if (lang === 'zh') {
    return {
      heading: '聚會時間',
      items: [
        { label: '主日崇拜：上午 10:00' },
